<?php require_once __DIR__.'/../includes/functions.php';require_admin();require_role(['super_admin','admin','finance_admin']);if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();foreach($_POST['m']??[] as $id=>$fee)db()->prepare("UPDATE membership_types SET annual_fee=? WHERE id=?")->execute([$fee,$id]);foreach($_POST['v']??[] as $id=>$r)db()->prepare("UPDATE village_space_types SET price_member=?,price_non_member=? WHERE id=?")->execute([$r['member'],$r['nonmember'],$id]);flash('success','Fees saved');redirect('/admin/fees.php');}$m=db()->query("SELECT * FROM membership_types")->fetchAll();$v=db()->query("SELECT * FROM village_space_types")->fetchAll();include __DIR__.'/../includes/header.php';?><div class="admin"><?php include __DIR__.'/sidebar.php';?><main class="content"><h1>Fees</h1><form method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><h2>Membership</h2><table><?php foreach($m as $x):?><tr><td><?=h($x['name'])?></td><td><input name="m[<?=h($x['id'])?>]" value="<?=h($x['annual_fee'])?>"></td></tr><?php endforeach;?></table><h2>Village</h2><table><?php foreach($v as $x):?><tr><td><?=h($x['name'])?></td><td><input name="v[<?=h($x['id'])?>][member]" value="<?=h($x['price_member'])?>"></td><td><input name="v[<?=h($x['id'])?>][nonmember]" value="<?=h($x['price_non_member'])?>"></td></tr><?php endforeach;?></table><button>Save</button></form></main></div><?php include __DIR__.'/../includes/footer.php';?>